// Build order + items + cash_movement from Kira payload
const body = $('Webhook: kira-new-sale').first().json.body || $('Webhook: kira-new-sale').first().json;
const rateRow = $input.first().json || {};
const rate = rateRow.Bs != null ? parseFloat(rateRow.Bs) : null;

const client = body.client || {};
const delivery = body.delivery || {};
const payment = body.payment || {};
const items = Array.isArray(body.items) ? body.items : [];

const subtotalUsd = items.reduce((s, it) => s + (parseFloat(it.unit_price_usd || 0) * (parseInt(it.quantity || 1))), 0);
const deliveryCostUsd = parseFloat(delivery.cost_usd || 0);
const totalUsd = Math.round((subtotalUsd + deliveryCostUsd) * 100) / 100;
const totalBs = rate ? Math.round(totalUsd * rate * 100) / 100 : null;

const amountPaidUsd = parseFloat(payment.amount_usd || 0) || null;
const amountPaidBs = parseFloat(payment.amount_bs || 0) || null;
const paidUsdEq = (amountPaidUsd || 0) + (rate && amountPaidBs ? amountPaidBs / rate : 0);
const changeGiven = Math.max(0, Math.round((paidUsdEq - totalUsd) * 100) / 100);

const allowedMethods = ['cash','zelle','bolivares','binance','mixto'];
const paymentMethod = allowedMethods.includes(payment.method) ? payment.method : null;

const status = payment.method ? 'confirmado' : 'pendiente_pago';

const orderPayload = {
  order_number: body.order_number || null,
  client_name: client.name || null,
  client_phone: (client.phone || '').replace(/\s+/g,'') || null,
  client_city: client.city || null,
  client_cedula: client.cedula || null,
  channel: 'whatsapp',
  status,
  delivery_type: delivery.type || null,
  carrier: delivery.carrier || null,
  tracking_number: delivery.tracking_number || null,
  delivery_address: delivery.address || null,
  subtotal_usd: Math.round(subtotalUsd * 100) / 100 || null,
  delivery_cost_usd: deliveryCostUsd || 0,
  total_usd: totalUsd || null,
  total_bs: totalBs,
  exchange_rate: rate,
  payment_method: paymentMethod,
  amount_paid_usd: amountPaidUsd,
  amount_paid_bs: amountPaidBs,
  change_given: changeGiven,
  notes: body.notes || null,
  kira_conversation_id: body.kira_conversation_id || null
};

const lineItems = items.map(it => ({
  sku: it.sku || null,
  product_name: it.product_name || it.name || 'Producto',
  size: it.size || null,
  color: it.color || null,
  quantity: parseInt(it.quantity || 1),
  unit_price_usd: parseFloat(it.unit_price_usd || 0),
  unit_cost_usd: it.unit_cost_usd != null ? parseFloat(it.unit_cost_usd) : null,
  total_price_usd: Math.round(parseFloat(it.unit_price_usd || 0) * parseInt(it.quantity || 1) * 100) / 100
}));

return [{ json: { order: orderPayload, lineItems, payment, rate } }];

const inserted = $input.first().json;
const orderRow = Array.isArray(inserted) ? inserted[0] : inserted;
const orderId = orderRow.id;
const t = $('Transform Kira payload').first().json;
const itemRows = (t.lineItems || []).map(li => ({ ...li, order_id: orderId }));

// Build cash_movements (one per wallet used)
const cashRows = [];
const p = t.payment || {};
const rate = t.rate || null;
if (p.amount_usd) {
  const wallet = p.method === 'zelle' ? 'zelle' : 'cash_usd';
  cashRows.push({
    movement_type: 'ingreso',
    wallet,
    amount: parseFloat(p.amount_usd),
    exchange_rate: rate,
    amount_usd_equivalent: parseFloat(p.amount_usd),
    concept: 'Venta WhatsApp',
    order_id: orderId
  });
}
if (p.amount_bs) {
  cashRows.push({
    movement_type: 'ingreso',
    wallet: 'bolivares',
    amount: parseFloat(p.amount_bs),
    exchange_rate: rate,
    amount_usd_equivalent: rate ? Math.round((parseFloat(p.amount_bs) / rate) * 100) / 100 : null,
    concept: 'Venta WhatsApp',
    order_id: orderId
  });
}

return [{ json: { orderId, orderRow, itemRows, cashRows } }];

